import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { dashboardAPI } from '../api';

function StatCard({ icon, label, value, color }) {
  return (
    <div className={`panel p-5 border-l-4 ${color} fade-in`}>
      <div className="flex items-center gap-3">
        <span className="text-3xl">{icon}</span>
        <div>
          <p className="text-sm text-emerald-900/70">{label}</p>
          <p className="text-2xl font-bold text-emerald-950">{value}</p>
        </div>
      </div>
    </div>
  );
}

export default function Dashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    dashboardAPI.get().then(d => { setData(d); setLoading(false); });
  }, []);

  if (loading) return <div className="flex justify-center py-20 text-emerald-700/70 text-lg">Loading...</div>;

  const statusBadge = (status) => {
    const styles = { upcoming: 'bg-blue-100 text-blue-700', completed: 'bg-green-100 text-green-700', cancelled: 'bg-red-100 text-red-700' };
    return <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${styles[status] || ''}`}>{status}</span>;
  };

  return (
    <div className="space-y-6">
      <div className="panel-soft p-6 fade-in">
        <h1 className="title-xl">Dashboard</h1>
        <p className="text-sm text-emerald-900/70 mt-1">Track squads, match operations, and settlement health in one place.</p>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <StatCard icon="👥" label="Teams" value={data.totalTeams} color="border-emerald-500" />
        <StatCard icon="🧑‍🤝‍🧑" label="Players" value={data.totalPlayers} color="border-sky-500" />
        <StatCard icon="🏆" label="Matches" value={data.totalMatches} color="border-amber-500" />
        <StatCard icon="📅" label="Upcoming" value={data.upcomingMatches} color="border-violet-500" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="panel p-5 border-l-4 border-rose-400 fade-in">
          <p className="text-sm text-emerald-900/70">Total Expenses</p>
          <p className="text-2xl font-bold text-emerald-950">₹{data.totalExpenses.toFixed(2)}</p>
        </div>
        <div className="panel p-5 border-l-4 border-amber-500 fade-in">
          <p className="text-sm text-emerald-900/70">Unsettled Amount</p>
          <p className="text-2xl font-bold text-amber-600">₹{data.unsettledExpenses.toFixed(2)}</p>
        </div>
      </div>

      <div className="panel overflow-hidden fade-in">
        <div className="px-5 py-4 border-b border-emerald-100 flex items-center justify-between bg-emerald-50/60">
          <h2 className="font-semibold text-emerald-900">Recent Matches</h2>
          <Link to="/matches" className="text-sm text-emerald-700 hover:underline">View all →</Link>
        </div>
        {data.recentMatches.length === 0 ? (
          <div className="text-center py-10 text-emerald-800/50">
            <p className="text-4xl mb-2">🏏</p>
            <p>No matches yet. <Link to="/matches" className="text-emerald-700 hover:underline">Add your first match</Link></p>
          </div>
        ) : (
          <table className="w-full text-sm">
            <thead className="bg-emerald-50 text-emerald-900/65 text-xs uppercase">
              <tr>
                <th className="text-left px-5 py-3">Match</th>
                <th className="text-left px-5 py-3">Team</th>
                <th className="text-left px-5 py-3">Date</th>
                <th className="text-left px-5 py-3">Attended</th>
                <th className="text-left px-5 py-3">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {data.recentMatches.map(m => (
                <tr key={m.id} className="hover:bg-emerald-50/50">
                  <td className="px-5 py-3">
                    <Link to={`/matches/${m.id}`} className="font-medium text-emerald-800 hover:underline">
                      Match #{m.match_number} vs {m.opponent}
                    </Link>
                  </td>
                  <td className="px-5 py-3 text-emerald-900/80">{m.team_name}</td>
                  <td className="px-5 py-3 text-emerald-900/80">{new Date(m.match_date).toLocaleDateString()}</td>
                  <td className="px-5 py-3"><span className="font-medium text-emerald-700">{m.attended_count}</span> players</td>
                  <td className="px-5 py-3">{statusBadge(m.status)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
